onClick:
{{
  (async () => {
    // 1. LỚP BẢO VỆ: Chống click đúp bằng appsmith.store
    const lastClick = appsmith.store.lastReportTime || 0;
    const now = Date.now();

    // Nếu vừa bấm trong vòng 3 giây trước, chặn ngay lập tức
    if ((now - lastClick) < 3000) {
      showAlert("⚠️ Đang xử lý, vui lòng không bấm liên tục!", "warning");
      return;
    }

    // 2. KHÓA NÚT NGAY LẬP TỨC
    btn_SubmitBP.setDisabled(true);
    storeValue('lastReportTime', now);

    try {
      // 3. THU THẬP DỮ LIỆU
      const ma = inp_BP_Ma.text ? inp_BP_Ma.text.trim() : "";
      const sl = Number(inp_BP_SoLuong.text) || 0;
      const nguoidat = inp_BP_NguoiDat.text || "";

      // KIỂM TRA ĐẦU VÀO
      if (!ma || sl <= 0 || !nguoidat) {
        showAlert("❌ Vui lòng nhập đầy đủ Mã, Số lượng, Người thực hiện!", "error");
        btn_SubmitBP.setDisabled(false); // Mở khóa nếu nhập thiếu
        return;
      }

      // 4. RÀ SOÁT TỒN KHO
      const stock = await Get_Inventory_Status.run({ code: ma });
      if (!stock || stock[0].phu_tung + stock[0].cong_cu < sl) {
        showAlert("❌ Tồn kho không đủ để xuất phế!", "error");
        btn_SubmitBP.setDisabled(false); // Mở khóa
        return;
      }

      // 5. TÍNH TOÁN PHÂN BỔ
      const pt_ton = stock[0].phu_tung || 0;
      let deduct_pt = (sl <= pt_ton) ? sl : pt_ton;
      let deduct_cc = (sl <= pt_ton) ? 0 : (sl - pt_ton);

      // 6. GỌI DATABASE (Đã bao gồm BEGIN...COMMIT trong query)
      await Action_Process_Scrap.run({ 
        code: ma,
        name: inp_BP_Ten.text,
        unit: inp_BP_DonVi.text,
        qty: sl,
        emp: nguoidat,
        vitri: inp_BP_ViTri.text,
        nguoiduyet: inp_BP_NguoiDuyet.text,
        xuong: inp_BP_Xuong.text,
        loai: inp_BP_Loai.text,
        nguyennhan: inp_BP_NguyenNhan.text,
        trangthai: sel_BP_TrangThai.selectedOptionValue || "New",
        ghichu: inp_BP_GhiChu.text,
        qty_pt: deduct_pt,
        qty_cc: deduct_cc
      });

      // 7. THÀNH CÔNG -> MỚI RESET FORM
      await Get_Scrap_List.run(); 
      await Get_LS_Phe.run();
      resetWidget('Form1', true);
      showAlert("✅ Báo phế thành công!", "success");

    } catch (err) {
      console.error("LỖI GIAO DỊCH:", err);
      showAlert("❌ Lỗi hệ thống: " + err.message, "error");
    } finally {
      // Dù thành công hay thất bại, mở khóa nút sau 3s
      btn_SubmitBP.setDisabled(false);
    }
  })()
}}
